/**
 * ObjectEditor Component
 * Form for creating and editing objects
 */

import React, { useState, useEffect } from 'react';
import useWorldBuilderStore from '../store/store';
import '../styles/EntityEditor.css';

export default function ObjectEditor({ object, onSave, onCancel }) {
  const [formData, setFormData] = useState({
    vnum: '',
    keywords: '',
    short: '',
    long: '',
    description: '',
    weight: 0,
    cost: 0,
    type: 'general',
  });
  const [isEditing, setIsEditing] = useState(!object);

  useEffect(() => {
    if (object) {
      setFormData({
        vnum: object.vnum || '',
        keywords: object.keywords || '',
        short: object.short || '',
        long: object.long || '',
        description: object.description || '',
        weight: object.weight || 0,
        cost: object.cost || 0,
        type: object.type || 'general',
      });
      setIsEditing(false);
    } else {
      setIsEditing(true);
    }
  }, [object]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name.match(/^(weight|cost)$/) ? parseInt(value) || 0 : value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSave(formData);
    if (!object) {
      setFormData({
        vnum: '',
        keywords: '',
        short: '',
        long: '',
        description: '',
        weight: 0,
        cost: 0,
        type: 'general',
      });
    }
  };

  if (!object && !isEditing) {
    return (
      <div className="entity-editor">
        <div className="editor-empty">
          <p>Select an object to edit or create a new one</p>
          <button className="btn-primary" onClick={() => setIsEditing(true)}>
            + Create New Object
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="entity-editor">
      <div className="editor-header">
        <h3>{object ? `Object ${object.vnum}` : 'New Object'}</h3>
        {!isEditing && (
          <button className="btn-secondary" onClick={() => setIsEditing(true)}>
            Edit
          </button>
        )}
      </div>

      {isEditing ? (
        <form onSubmit={handleSubmit} className="editor-form">
          <div className="form-group">
            <label htmlFor="vnum">VNUM *</label>
            <input
              id="vnum"
              type="number"
              name="vnum"
              value={formData.vnum}
              onChange={handleChange}
              required
              disabled={!!object}
            />
          </div>

          <div className="form-group">
            <label htmlFor="keywords">Keywords *</label>
            <input
              id="keywords"
              type="text"
              name="keywords"
              value={formData.keywords}
              onChange={handleChange}
              placeholder="e.g., 'sword blade weapon' (space-separated)"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="short">Short Description *</label>
            <input
              id="short"
              type="text"
              name="short"
              value={formData.short}
              onChange={handleChange}
              placeholder="e.g., 'a bright longsword'"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="long">Long Description</label>
            <textarea
              id="long"
              name="long"
              value={formData.long}
              onChange={handleChange}
              placeholder="Shown when examining the object"
              rows="4"
            />
          </div>

          <div className="form-group">
            <label htmlFor="type">Type</label>
            <select
              id="type"
              name="type"
              value={formData.type}
              onChange={handleChange}
            >
              <option value="general">General</option>
              <option value="weapon">Weapon</option>
              <option value="armor">Armor</option>
              <option value="potion">Potion</option>
              <option value="scroll">Scroll</option>
              <option value="food">Food</option>
              <option value="treasure">Treasure</option>
              <option value="furniture">Furniture</option>
              <option value="key">Key</option>
            </select>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label htmlFor="weight">Weight</label>
              <input
                id="weight"
                type="number"
                name="weight"
                value={formData.weight}
                onChange={handleChange}
                min="0"
              />
            </div>
            <div className="form-group">
              <label htmlFor="cost">Cost</label>
              <input
                id="cost"
                type="number"
                name="cost"
                value={formData.cost}
                onChange={handleChange}
                min="0"
              />
            </div>
          </div>

          <div className="form-group">
            <label htmlFor="description">Description</label>
            <textarea
              id="description"
              name="description"
              value={formData.description}
              onChange={handleChange}
              placeholder="Internal notes"
              rows="3"
            />
          </div>

          <div className="form-actions">
            <button type="submit" className="btn-primary">
              {object ? 'Update' : 'Create'}
            </button>
            <button
              type="button"
              className="btn-secondary"
              onClick={() => {
                if (object) {
                  setIsEditing(false);
                } else {
                  onCancel();
                }
              }}
            >
              Cancel
            </button>
          </div>
        </form>
      ) : (
        <div className="editor-view">
          <div className="view-field">
            <strong>VNUM:</strong> {formData.vnum}
          </div>
          <div className="view-field">
            <strong>Keywords:</strong> {formData.keywords}
          </div>
          <div className="view-field">
            <strong>Short:</strong> {formData.short}
          </div>
          {formData.long && (
            <div className="view-field">
              <strong>Long:</strong>
              <pre>{formData.long}</pre>
            </div>
          )}
          {formData.type && (
            <div className="view-field">
              <strong>Type:</strong> {formData.type}
            </div>
          )}
          <div className="view-row">
            <div className="view-field">
              <strong>Weight:</strong> {formData.weight}
            </div>
            <div className="view-field">
              <strong>Cost:</strong> {formData.cost}
            </div>
          </div>
          {formData.description && (
            <div className="view-field">
              <strong>Notes:</strong> {formData.description}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
